// Merge client-level values into each role at read time, so the rest of the
// app can keep treating a role as self-contained.
export function getClient(code) {
  const c = CLIENTS[(code || "").trim()];
  if (!c) return null;
  // demo passthrough
  let base = c;
  if ((!c.roles || c.roles.length === 0) && (!c.values || c.values.length === 0)) {
    const first = Object.values(CLIENTS).find((x) => x.roles && x.roles.length > 0);
    if (first) base = { ...c, values: first.values, roles: first.roles, branding: c.branding };
  }
  const values = base.values || [];
  const roles = (base.roles || []).map((r) => ({ ...r, values: r.values || values }));
  return {
    company: base.company,
    branding: base.branding || null,
    why: base.why || "",
    piTargetSummary: base.piTargetSummary || "",
    piTier: base.piTier || "none",
    // assessment — which fit-assessment a client owns: "none" | "bryq" | "pi".
    // Explicit field, hard "none" default (never derived live from piTier).
    // Set by the cockpit Plan picker; migrated onto existing records once.
    assessment: base.assessment || "none",
    // compareEnabled — whether the cockpit has turned on candidate comparison
    // for this client. Explicit boolean, hard FALSE default (feature is off for
    // every client until deliberately switched on in the cockpit). Behaves
    // exactly like `assessment`: threaded through all three read-homes here plus
    // the config.js response. Gates the comparison surface, nothing else.
    compareEnabled: base.compareEnabled === true,
    // calendlyUrl — the client owner's Calendly event-type link, pasted once in
    // the cockpit. Null until connected. This is the Tier-1 "paste-the-link"
    // scheduling model (per-client, owner-minted; see the scheduling arc in
    // ROADMAP_ARC.md). Threaded through all THREE read-homes here plus the
    // config.js response — same allowlist discipline as compareEnabled.
    calendlyUrl: base.calendlyUrl || null,
    // physicalAddress — the client's business mailing address (CAN-SPAM: required
    // in every candidate email; white-label sends as the client). null until set.
    physicalAddress: base.physicalAddress || null,
    // postingLocation — the client's DEFAULT job-posting location, STRUCTURED
    // ({ city, state, zip, country }) because job boards require discrete
    // fields (unlike physicalAddress, which is opaque CAN-SPAM mailing text and
    // must NOT be parsed for this). A seat's own location overrides this; this
    // is the client-wide default a single-location trades shop sets once. null
    // until set → the feed emits its honest "provisional" placeholder.
    postingLocation: base.postingLocation || null,
    // comms — client-level candidate-communication config, CHANNEL-KEYED so SMS
    // reuses the shape (SPEC_candidate_communication_MASTER §3, "built once,
    // every channel rides it"). null = comms off for this client.
    //   { email: { enabled, fromName, fromAddress, replyTo }, sms: {…later} }
    // fromName is owner-set ("Summit Mechanical via Hire2Scale"); fromAddress/
    // replyTo are Hire2Scale's verified domain until counsel clears client-domain
    // send (§4.2, counsel #1). physicalAddress (separate allowlist home) is the
    // CAN-SPAM footer; this is the from-line. Per-candidate consent/suppression/
    // log do NOT live here — they're on the applicant record (ATS-owned; §3.1).
    // Threaded through all THREE read-homes here plus the config.js response.
    comms: base.comms || null,
    // JobTarget company link (see normalize() note). null until linked.
    jobTargetCompanyId: base.jobTargetCompanyId || null,
    // businessContext — the onboarding wizard's site-read inferences, persisted
    // first-class so the AI work is done ONCE and reused by every downstream
    // generator (Culture Codified expander, playbook prose, job ads):
    //   { industry, subType, whatYouDo, customerWord, frontlineUnit, voice }
    // customerWord ("homeowners") and frontlineUnit ("the jobsite") are load-
    // bearing — they appear in every expander-drafted behavior line. Grouped
    // object = ONE allowlist entry (comms/postingLocation precedent); future
    // context fields land inside without new allowlist work. Hard null default.
    businessContext: base.businessContext || null,
    // culture — Culture Codified identity fields: { acronym, purpose, mission }.
    // Distinct from `why` (which stays untouched). Drafted by the expander from
    // businessContext when blank, owner-confirmed. Hard null default. Threaded
    // through all THREE read-homes here plus the config.js response — same
    // allowlist discipline as comms.
    culture: base.culture || null,
    values,
    roles,
  };
}

// ════════════════════════════════════════════════════════════════════════
//  COCKPIT: async resolver — Redis first, in-code CLIENTS as fallback
// ════════════════════════════════════════════════════════════════════════
//  getClient (above) is the SYNCHRONOUS in-code fallback and is left exactly
//  as it was. resolveClient is the new ASYNC path used by the API handlers:
//  it reads a client record from Redis, and if there isn't one (or Redis is
//  unreachable), it falls back to getClient. This is how the live Contractor
//  Dynamics flow keeps working even before/without migration.
//
//  Same shape-normalization as getClient: client-level values are merged into
//  any role that doesn't define its own. A client that is explicitly disabled
//  in Redis (enabled === false) resolves to null, exactly like a missing code.

function normalize(rec) {
  if (!rec) return null;
  const values = rec.values || [];
  const roles = (rec.roles || []).map((r) => ({ ...r, values: r.values || values }));
  return {
    company: rec.company,
    branding: rec.branding || null,
    why: rec.why || "",
    piTargetSummary: rec.piTargetSummary || "",
    piTier: rec.piTier || "none",
    assessment: rec.assessment || "none",
    // compareEnabled — cockpit candidate-comparison toggle for this client.
    // Hard FALSE default; only true when the Redis record explicitly sets it.
    // This is the path resolveClient actually uses live, so this line is what
    // makes the flag real for a deployed client.
    compareEnabled: rec.compareEnabled === true,
    // calendlyUrl — Tier-1 scheduling link for this client (owner-pasted). Hard
    // null default; only set when the Redis record carries it. This is the path
    // resolveClient uses live, so this line makes the link real for a deployed client.
    calendlyUrl: rec.calendlyUrl || null,
    physicalAddress: rec.physicalAddress || null,
    // postingLocation — structured default job-posting location (see getClient).
    // Live path via resolveClient; makes the field real for a deployed client.
    postingLocation: rec.postingLocation || null,
    // comms — client-level comms config (channel-keyed; see getClient note).
    // Live path via resolveClient; makes the field real for a deployed client.
    comms: rec.comms || null,
    // JobTarget company link — the JobTarget-side companyId for this client,
    // set by the JobTarget provisioning flow (confirm/provision). Read-out
    // allowlist entry so handlers can SEE it; null until a company is linked.
    jobTargetCompanyId: rec.jobTargetCompanyId || null,
    // businessContext — wizard site-read inferences (see getClient note). This
    // is the path resolveClient uses live, so this line makes the context real
    // for a deployed client. Hard null default.
    businessContext: rec.businessContext || null,
    // culture — Culture Codified identity fields (see getClient note). Live
    // path via resolveClient; makes the field real for a deployed client.
    culture: rec.culture || null,
    values,
    roles,
  };
}

export async function resolveClient(code) {
  const c = (code || "").trim();
  if (!c) return null;
  try {
    const { getClientRecord } = await import("./api/_lib/store.js");
    const rec = await getClientRecord(c);
    if (rec) {
      if (rec.enabled === false) return null; // explicitly disabled
      if (rec.status === "archived" || rec.status === "deleted") return null; // hidden / removed from cockpit — no portal login
      return normalize(rec);
    }
  } catch (e) {
    // Redis unreachable or store unavailable — fall through to in-code.
  }
  return getClient(c);
}

// The in-code clients as a flat list of { code, ...record } — used to seed
// Redis once on first cockpit load.
export function inCodeClientList() {
  return Object.entries(CLIENTS).map(([code, rec]) => ({
    code,
    company: rec.company || "",
    branding: rec.branding || null,
    why: rec.why || "",
    piTargetSummary: rec.piTargetSummary || "",
    piTier: rec.piTier || "none",
    assessment: rec.assessment || "none",
    // compareEnabled — carried into the one-time Redis seed so an in-code client
    // that sets it keeps the flag after migration. Hard FALSE default.
    compareEnabled: rec.compareEnabled === true,
    // calendlyUrl — carried into the one-time Redis seed so an in-code client
    // that sets it keeps the link after migration. Hard null default.
    calendlyUrl: rec.calendlyUrl || null,
    physicalAddress: rec.physicalAddress || null,
    postingLocation: rec.postingLocation || null,
    // comms — client-level comms config, carried into the one-time Redis seed so
    // an in-code client that sets it keeps the config after migration. Hard null.
    comms: rec.comms || null,
    jobTargetCompanyId: rec.jobTargetCompanyId || null,
    // businessContext + culture — carried into the one-time Redis seed so an
    // in-code client that sets them keeps them after migration. Hard null.
    businessContext: rec.businessContext || null,
    culture: rec.culture || null,
    values: rec.values || [],
    roles: rec.roles || [],
  }));
}
